public class Student {
    int rollNumber;
    String name;
    int age;
    String branch;
    double percentage;

    Student(int rollNumber, String name, int age, String branch, double percentage) {
        this.rollNumber = rollNumber;
        this.name = name;
        this.age = age;
        this.branch = branch;
        this.percentage = percentage;
    }

    void display() {
        System.out.printf("Roll: %d | %s | Age: %d | %s | %.2f%%%n",
                rollNumber, name, age, branch, percentage);
    }

    boolean isPass() {
        return percentage >= 40;
    }

    String getGrade() {
        if (percentage >= 90) return "A";
        if (percentage >= 80) return "B";
        if (percentage >= 70) return "C";
        if (percentage >= 60) return "D";
        return "F";
    }
}

