public class Employee {
    int id;
    String name;
    String department;
    double basicSalary;

    Employee(int id, String name, String department, double basicSalary) {
        this.id = id;
        this.name = name;
        this.department = department;
        this.basicSalary = basicSalary;
    }

    double calculateHRA() { return basicSalary * 0.10; }
    double calculateDA() { return basicSalary * 0.05; }
    double calculateGrossSalary() {
        return basicSalary + calculateHRA() + calculateDA();
    }

    void displayPayslip() {
        System.out.println("--- Payslip ---");
        System.out.println("ID: " + id + " | " + name + " | " + department);
        System.out.printf("Basic: Rs. %.2f%n", basicSalary);
        System.out.printf("HRA  : Rs. %.2f%n", calculateHRA());
        System.out.printf("DA   : Rs. %.2f%n", calculateDA());
        System.out.printf("Gross: Rs. %.2f%n", calculateGrossSalary());
    }

    public static void main(String[] args) {
        Employee e1 = new Employee(101, "Amit", "IT", 50000);
        e1.displayPayslip();
    }
}

