public class Car {
    String brand, model;
    int year;
    double price;
    boolean isRunning = false;

    Car(String brand, String model, int year, double price) {
        this.brand = brand;
        this.model = model;
        this.year = year;
        this.price = price;
    }

    void start() {
        if (!isRunning) {
            isRunning = true;
            System.out.println(brand + " " + model + " started.");
        } else System.out.println("Already running.");
    }

    void stop() {
        if (isRunning) {
            isRunning = false;
            System.out.println(brand + " " + model + " stopped.");
        }
    }

    void displayInfo() {
        System.out.printf("%s %s (%d) - Rs. %.0f | Running: %s%n",
                brand, model, year, price, isRunning);
    }

    public static void main(String[] args) {
        Car c = new Car("Hyundai", "i20", 2022, 850000);
        c.displayInfo();
        c.start();
        c.start();
        c.stop();
    }
}

