public class BankAccount {
    String accountNumber;
    String holderName;
    double balance;

    BankAccount(String accountNumber, String holderName, double openingBalance) {
        this.accountNumber = accountNumber;
        this.holderName = holderName;
        this.balance = openingBalance >= 0 ? openingBalance : 0;
    }

    void deposit(double amount) {
        if (amount <= 0) System.out.println("Invalid deposit amount.");
        else { balance += amount; System.out.printf("Deposited Rs. %.2f%n", amount); }
    }

    void withdraw(double amount) {
        if (amount <= 0) System.out.println("Invalid amount.");
        else if (amount > balance) System.out.println("Insufficient balance.");
        else { balance -= amount; System.out.printf("Withdrawn Rs. %.2f%n", amount); }
    }

    double getBalance() { return balance; }

    void displayAccount() {
        System.out.printf("[%s] %s - Balance: Rs. %.2f%n", accountNumber, holderName, balance);
    }

    public static void main(String[] args) {
        BankAccount acc = new BankAccount("ACC001", "Riya", 10000);
        acc.deposit(5000);
        acc.withdraw(2000);
        acc.withdraw(50000);
        acc.displayAccount();
    }
}

