public class Product {
    int id;
    String name, category;
    double price;
    int quantity;

    Product(int id, String name, String category, double price, int quantity) {
        this.id = id;
        this.name = name;
        this.category = category;
        this.price = price;
        this.quantity = quantity;
    }

    double getDiscountedPrice(double discountPercent) {
        if (discountPercent < 0 || discountPercent > 100) return price;
        return price * (1 - discountPercent / 100.0);
    }

    double getTotalValue() { return price * quantity; }

    boolean sell(int amount) {
        if (amount <= 0 || amount > quantity) return false;
        quantity -= amount;
        return true;
    }

    void restock(int amount) {
        if (amount > 0) quantity += amount;
    }

    void displayProduct() {
        System.out.printf("[%d] %s (%s) - Rs. %.2f x %d = Rs. %.2f%n",
                id, name, category, price, quantity, getTotalValue());
    }

    public static void main(String[] args) {
        Product p = new Product(1, "Notebook", "Stationery", 50, 100);
        p.displayProduct();
        p.sell(10);
        System.out.printf("After 10%% off: Rs. %.2f%n", p.getDiscountedPrice(10));
        p.displayProduct();
    }
}

