class Book {
    String title, author, isbn;
    boolean isAvailable = true;

    Book(String title, String author, String isbn) {
        this.title = title;
        this.author = author;
        this.isbn = isbn;
    }

    void display() {
        System.out.println(title + " by " + author + " [" + isbn + "] - "
                + (isAvailable ? "Available" : "Issued"));
    }
}

public class Library {
    Book[] books = new Book[50];
    int bookCount = 0;

    void addBook(Book b) {
        if (bookCount < books.length) books[bookCount++] = b;
    }

    void displayAllBooks() {
        for (int i = 0; i < bookCount; i++) books[i].display();
    }

    boolean issueBook(String isbn) {
        for (int i = 0; i < bookCount; i++) {
            if (books[i].isbn.equals(isbn) && books[i].isAvailable) {
                books[i].isAvailable = false;
                return true;
            }
        }
        return false;
    }

    public static void main(String[] args) {
        Library lib = new Library();
        lib.addBook(new Book("Java Basics", "Joshua Bloch", "ISBN001"));
        lib.addBook(new Book("Clean Code", "Robert Martin", "ISBN002"));
        lib.displayAllBooks();
        lib.issueBook("ISBN001");
        lib.displayAllBooks();
    }
}

