public class StudentManagementSystem {
    static Student[] students = new Student[100];
    static int count = 0;
    static Scanner sc = new Scanner(System.in);

    static void addStudent() {
        System.out.print("Roll: "); int roll = sc.nextInt();
        sc.nextLine();
        for (int i = 0; i < count; i++) {
            if (students[i].rollNumber == roll) {
                System.out.println("Roll number exists!"); return;
            }
        }
        System.out.print("Name: "); String name = sc.nextLine();
        System.out.print("Age: "); int age = sc.nextInt();
        sc.nextLine();
        System.out.print("Branch: "); String branch = sc.nextLine();
        System.out.print("Percentage: "); double pct = sc.nextDouble();
        students[count++] = new Student(roll, name, age, branch, pct);
        System.out.println("Student added.");
    }

    static void displayAll() {
        if (count == 0) { System.out.println("No students."); return; }
        for (int i = 0; i < count; i++) students[i].display();
    }

    public static void main(String[] args) {
        boolean running = true;
        while (running) {
            System.out.println("\n1.Add 2.Display 3.Search 4.Toppers 5.Exit");
            int ch = sc.nextInt();
            switch (ch) {
                case 1: addStudent(); break;
                case 2: displayAll(); break;
                case 5: running = false; break;
                default: System.out.println("Try again.");
            }
        }
        sc.close();
    }
}

