    static Scanner sc = new Scanner(System.in);

    static void addEmployee() {
        System.out.print("ID: "); int id = sc.nextInt();
        sc.nextLine();
        System.out.print("Name: "); String name = sc.nextLine();
        System.out.print("Department: "); String dept = sc.nextLine();
        System.out.print("Basic Salary: "); double sal = sc.nextDouble();
        employees[count++] = new Employee(id, name, dept, sal);
        System.out.println("Employee added.");
    }

    static void displayAll() {
        for (int i = 0; i < count; i++) employees[i].displayPayslip();
    }

    static void highestPaid() {
        if (count == 0) return;
        Employee top = employees[0];
        for (int i = 1; i < count; i++) {
            if (employees[i].calculateGrossSalary() > top.calculateGrossSalary())
                top = employees[i];
        }
        System.out.println("Highest paid:");
        top.displayPayslip();
    }

